import React, { useState, useEffect, useContext } from "react";
export function Header() {
    const { user, login, logout, signup } = useContext(AuthContext);
    const [showModal, setShowModal] = useState(false);
    const [form, setForm] = useState({ email: "", password: "", username: "" });
    const [isSignup, setIsSignup] = useState(false);
    const [error, setError] = useState("");

    const handleChange = (e) => {
        const { name, value } = e.target;
        setForm(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (isSignup) {
            const result = await signup(form.email, form.password, form.username);
            if (!result.success) setError(result.message);
            else setShowModal(false);
        } else {
            const result = await login(form.email, form.password);
            if (!result.success) {
                if (result.newUser) setIsSignup(true);
                else setError(result.message);
            } else {
                setShowModal(false);
            }
        }
    };

    return (
        <header style={headerStyles.header}>
            <h2 style={{ color: "#fff" }}>My Dashboard</h2>
            {user ? (
                <button style={headerStyles.button} onClick={logout}>Logout</button>
            ) : (
                <button style={headerStyles.button} onClick={() => setShowModal(true)}>Login</button>
            )}

            {showModal && (
                <div style={headerStyles.modalOverlay}>
                    <div style={headerStyles.modalContent}>
                        <h3>{isSignup ? "Sign Up" : "Login"}</h3>
                        {error && <p style={{ color: "red" }}>{error}</p>}
                        <form onSubmit={handleSubmit}>
                            {isSignup && (
                                <input
                                    name="username"
                                    placeholder="Username"
                                    value={form.username}
                                    onChange={handleChange}
                                    required
                                    style={headerStyles.input}
                                />
                            )}
                            <input
                                name="email"
                                placeholder="Email"
                                type="email"
                                value={form.email}
                                onChange={handleChange}
                                required
                                style={headerStyles.input}
                            />
                            <input
                                name="password"
                                placeholder="Password"
                                type="password"
                                value={form.password}
                                onChange={handleChange}
                                required
                                style={headerStyles.input}
                            />
                            <button type="submit" style={headerStyles.submitBtn}>
                                {isSignup ? "Sign Up" : "Login"}
                            </button>
                            <button type="button" onClick={() => setShowModal(false)} style={headerStyles.cancelBtn}>
                                Cancel
                            </button>
                        </form>
                    </div>
                </div>
            )}
        </header>
    );
}

const headerStyles = {
    header: {
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        padding: "10px 20px",
        backgroundColor: "#D50032",
        position: "fixed",
        width: "100%",
        top: 0,
        zIndex: 1000,
    },
    button: { padding: "5px 10px", borderRadius: "4px", cursor: "pointer", border: "none", backgroundColor: "#fff", color: "#D50032" },
    modalOverlay: { position: "fixed", top: 0, left: 0, right: 0, bottom: 0, backgroundColor: "rgba(0,0,0,0.5)", display: "flex", justifyContent: "center", alignItems: "center" },
    modalContent: { backgroundColor: "#fff", padding: "20px", borderRadius: "6px", width: "400px", maxWidth: "90%" },
    input: { width: "100%", padding: "8px", marginBottom: "10px", borderRadius: "4px", border: "1px solid #ccc" },
    submitBtn: { padding: "8px 12px", marginRight: "10px", backgroundColor: "#D50032", color: "#fff", border: "none", borderRadius: "4px", cursor: "pointer" },
    cancelBtn: { padding: "8px 12px", backgroundColor: "#ccc", color: "#000", border: "none", borderRadius: "4px", cursor: "pointer" },
};

export default Header;
